import React, { useEffect, useState } from 'react';
import { getEvents } from './api';

function App() {
    const [events, setEvents] = useState([]);

    useEffect(() => {
        getEvents().then(data => setEvents(data));
    }, []);

    return (
        <div>
            <h1>Список мероприятий</h1>
            <ul>
                {events.map(event => (
                    <li key={event.id}>{event.name}</li>
                ))}
            </ul>
        </div>
    );
}

export default App;
